import org.owasp.encoder.Encode;

import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        System.out.println("Hello, " + userInput + "!");

        // Properly encoding user input before outputting it to the HTML response
        String encodedUserInput = Encode.forHtml(userInput);
        System.out.println("<div>Welcome, " + encodedUserInput + "!</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
